// 6 · Anahtar kelime filtresi (FETÖ konusu) — genişletilebilir
const ANAHTAR = ["fetö","feto","fethullahçı","fetullahçı","gülen","gulen","bylock","15 temmuz","darbe girişimi","paralel yapı"];
const HARIC = [];
return items.filter(({ json }) => {
  const m = `${json.title||json.baslik||""} ${json.contentSnippet||json.ozet||""} ${json.content||json.icerik||""}`.toLowerCase();
  return ANAHTAR.some(k=>m.includes(k)) && !HARIC.some(k=>m.includes(k));
});

// 7 · URL bazında tam tekrar kontrolü (statik veri — hızlı başlangıç)
const store = $getWorkflowStaticData('global');
store.gorulenUrller = store.gorulenUrller || {};
const yeni = [];
for (const item of items) {
  const u = (item.json.link || item.json.orijinal_url || "").trim();
  if (!u) continue;
  if (store.gorulenUrller[u]) continue;
  store.gorulenUrller[u] = Date.now();
  item.json.orijinal_url = u;
  yeni.push(item);
}
return yeni;

// 8 · Story clustering: aynı olayı tek dosyada grupla (tekrarları SİLME, kaynak ekle)
function tokens(s){return (s||"").toLowerCase().replace(/[^a-z0-9çğıöşü ]/g," ").split(/\s+/).filter(w=>w.length>3);}
function jaccard(a,b){const A=new Set(a),B=new Set(b);const k=[...A].filter(x=>B.has(x)).length;return k/((A.size+B.size-k)||1);}
const ESIK=0.45; const kumeler=[];
for (const it of items){
  const j=it.json;
  const t=tokens(`${j.title||j.baslik} ${j.contentSnippet||j.ozet}`);
  let yer=false;
  for (const k of kumeler){ if (jaccard(t,k.tokens)>=ESIK){ k.kaynaklar.push({kaynak_adi:j.kaynak_adi||j.ad,orijinal_url:j.orijinal_url,yayin_tarihi:j.isoDate||j.yayin_tarihi}); yer=true; break; } }
  if(!yer) kumeler.push({tokens:t,baslik:j.title||j.baslik,icerik:j.content||j.icerik||j.contentSnippet||"",kaynaklar:[{kaynak_adi:j.kaynak_adi||j.ad,orijinal_url:j.orijinal_url,yayin_tarihi:j.isoDate||j.yayin_tarihi}]});
}
return kumeler.map(k=>({json:{baslik:k.baslik,icerik:k.icerik,kaynaklar:k.kaynaklar}}));

