// 11 · AI çıktısını doğrula + WP REST payload üret (güvenli varsayılanlar)
const out=[];
for (const it of items){
  const ham = it.json?.content?.[0]?.text ?? it.json.ai_text ?? "";
  let a=null; try{ a=JSON.parse(ham);}catch(e){ a=null; }
  const gecerli=new Set(["dogru","kismen_dogru","yanlis","dogrulanamaz","gorus"]);
  const iddialar=(a?.iddialar||[]).map(x=>({iddia_metni:String(x.iddia_metni||"").slice(0,2000),siniflandirma:gecerli.has(x.siniflandirma)?x.siniflandirma:"dogrulanamaz",gerekce:String(x.gerekce||""),dayanak_kaynak_url:x.dayanak_kaynak_url||""}));
  const isim = a?.isim_verilen_suclama==="hayir"?"hayir":"evet"; // emin değilsek hukuk kapısını AÇ
  out.push({json:{ title:(it.json.baslik||a?.ozet||"Başlıksız dosya").slice(0,120), status:"draft", content:"Otomatik üretilmiş TASLAK — editör/hukuk incelemesi bekliyor.", meta:{ haberler_ozet:a?.ozet||"", haberler_isim_verilen_suclama:isim, haberler_isim_suclama_gerekce:a?.isim_verilen_suclama_gerekce||"", haberler_kaynaklar:JSON.stringify(it.json.kaynaklar||[]), haberler_iddialar:JSON.stringify(iddialar) } }});
}
return out;
